// ── Parse & validate input from Master Orchestrator ──────────────────────────
const body = $input.first().json.body || $input.first().json;

const lat          = parseFloat(body.lat  || body.latitude  || 0);
const lng          = parseFloat(body.lng  || body.longitude || 0);
const businessType = String(body.businessType || body.business_type || 'other').toLowerCase();
const area         = String(body.area   || body.suburb || '');
const city         = String(body.city   || '');
const reportId     = String(body.reportId || body.report_id || '');

// ── Radius lookup (metres) — must match lib/compute/benchmarks.ts ─────────────
const RADIUS_MAP = {
  gym:        1500,
  fitness:    1500,
  cafe:       600,
  restaurant: 600,
  bakery:     600,
  bar:        600,
  salon:      600,
  retail:     500,
  takeaway:   500,
  pharmacy:   800
};

function resolveKey(bt) {
  const keys = Object.keys(RADIUS_MAP);
  for (let i = 0; i < keys.length; i++) {
    if (bt.indexOf(keys[i]) !== -1) return keys[i];
  }
  return 'other';
}

const bizKey = resolveKey(businessType);
const radius = RADIUS_MAP[bizKey] || 600;

// ── Google Places primary type ─────────────────────────────────────────────────
const TYPE_MAP = {
  gym:        'gym',
  fitness:    'gym',
  cafe:       'cafe',
  restaurant: 'restaurant',
  bakery:     'bakery',
  bar:        'bar',
  salon:      'beauty_salon',
  retail:     'clothing_store',
  takeaway:   'meal_takeaway',
  pharmacy:   'pharmacy'
};

// ── Keyword searches — catches places with non-standard Google type tags ───────
const KEYWORD_MAP = {
  gym:        ['fitness centre', 'health club', 'yoga studio', 'pilates', 'crossfit'],
  fitness:    ['fitness centre', 'health club', 'yoga studio', 'pilates'],
  cafe:       ['coffee shop', 'espresso bar', 'brunch cafe'],
  restaurant: ['restaurant', 'dining'],
  bakery:     ['bakery', 'patisserie'],
  bar:        ['bar', 'pub', 'tavern'],
  salon:      ['hair salon', 'barber', 'beauty salon'],
  retail:     ['clothing store', 'boutique'],
  takeaway:   ['takeaway', 'fast food'],
  pharmacy:   ['pharmacy', 'chemist']
};

const primaryType = TYPE_MAP[bizKey] || null;
const keywords    = (KEYWORD_MAP[bizKey] || []).slice(0, 2);

if (!lat || !lng) {
  throw new Error('A1: lat/lng missing from input — check Master Orchestrator coordinate passing');
}

return [{
  json: {
    lat, lng, bizKey, businessType, area, city, reportId,
    radius, primaryType, keywords,
    locationString: lat + ',' + lng
  }
}];

// ── Collect all results from 3 parallel NearbySearch calls ───────────────────
const allPlaces = [];

for (let i = 0; i < $input.all().length; i++) {
  const item = $input.all()[i].json;
  const results = item.results || item.result || [];
  for (let j = 0; j < results.length; j++) {
    allPlaces.push(results[j]);
  }
}

// ── Deduplicate by place_id ───────────────────────────────────────────────────
const seen = {};
const unique = [];
for (let i = 0; i < allPlaces.length; i++) {
  const p = allPlaces[i];
  const key = p.place_id || p.name || ('idx-' + i);
  if (!seen[key]) {
    seen[key] = true;
    unique.push(p);
  }
}

// ── Haversine distance calculation ───────────────────────────────────────────
const originLat = parseFloat($('Parse Input').first().json.lat);
const originLng = parseFloat($('Parse Input').first().json.lng);

function haversineM(lat1, lng1, lat2, lng2) {
  const R = 6371000;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLng = (lng2 - lng1) * Math.PI / 180;
  const a = Math.sin(dLat/2) * Math.sin(dLat/2)
    + Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180)
    * Math.sin(dLng/2) * Math.sin(dLng/2);
  return Math.round(R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a)));
}

// ── Scoring function: 0–100, higher = stronger threat ────────────────────────
// Components:
//   Rating    0–35 pts  (Google rating × 7)
//   Reviews   0–25 pts  (caps at 300 reviews = full score)
//   Proximity 0–30 pts  (closer to origin = higher score)
//   Operating   +10 pts (bonus if OPERATIONAL)
function scoreCompetitor(c, radius) {
  let score = 0;

  if (c.rating && c.rating > 0) {
    score += (c.rating / 5) * 35;
  }

  if (c.review_count && c.review_count > 0) {
    score += Math.min(c.review_count / 300, 1) * 25;
  }

  if (c.distance_m !== null && c.distance_m !== undefined && radius > 0) {
    const proximity = Math.max(0, 1 - c.distance_m / radius);
    score += proximity * 30;
  }

  if (c.business_status === 'OPERATIONAL') {
    score += 10;
  }

  return Math.round(Math.min(score, 100));
}

// ── Build competitor objects ──────────────────────────────────────────────────
const bizKey = $('Parse Input').first().json.bizKey;
const radius = $('Parse Input').first().json.radius;
const area   = $('Parse Input').first().json.area;
const city   = $('Parse Input').first().json.city;

const competitors = unique.map(function(p) {
  const loc = p.geometry && p.geometry.location ? p.geometry.location : {};
  const distM = (loc.lat && loc.lng)
    ? haversineM(originLat, originLng, loc.lat, loc.lng)
    : null;

  return {
    name:            p.name || 'Unknown',
    address:         p.vicinity || p.formatted_address || null,
    rating:          p.rating || null,
    review_count:    p.user_ratings_total || null,
    google_types:    p.types || [],
    place_id:        p.place_id || null,
    distance_m:      distM,
    competitor_type: 'direct',
    business_status: p.business_status || null
  };
}).filter(function(c) {
  return c.business_status !== 'PERMANENTLY_CLOSED';
});

// ── Score each competitor ─────────────────────────────────────────────────────
const scored = competitors.map(function(c) {
  c.threat_score = scoreCompetitor(c, radius);
  return c;
});

// ── Sort strongest → weakest ──────────────────────────────────────────────────
scored.sort(function(a, b) { return b.threat_score - a.threat_score; });

// ── Add rank + threat label ───────────────────────────────────────────────────
const ranked = scored.map(function(c, idx) {
  c.rank         = idx + 1;
  c.threat_label = c.threat_score >= 70 ? 'strong'
                 : c.threat_score >= 40 ? 'moderate'
                 : 'weak';
  return c;
});

// ── Location-level opportunity assessment ─────────────────────────────────────
const totalCount    = ranked.length;
const strongCount   = ranked.filter(function(c) { return c.threat_score >= 70; }).length;
const moderateCount = ranked.filter(function(c) { return c.threat_score >= 40 && c.threat_score < 70; }).length;

let opportunityLevel;
if (totalCount === 0) {
  opportunityLevel = 'unknown';
} else if (strongCount >= 3 || totalCount >= 8) {
  opportunityLevel = 'low';
} else if (strongCount >= 1 || moderateCount >= 3 || totalCount >= 4) {
  opportunityLevel = 'medium';
} else {
  opportunityLevel = 'high';
}

let opportunityReason;
if (opportunityLevel === 'unknown') {
  opportunityReason = 'No competitors detected — verify locally before treating as blue ocean. Data may be incomplete.';
} else if (opportunityLevel === 'low') {
  opportunityReason = strongCount + ' strong competitor(s) within ' + radius + 'm. Market is saturated — strong differentiation required.';
} else if (opportunityLevel === 'medium') {
  opportunityReason = totalCount + ' competitor(s) found (' + strongCount + ' strong, ' + moderateCount + ' moderate). Opportunity exists with clear positioning.';
} else {
  opportunityReason = 'Only ' + totalCount + ' weak competitor(s) within ' + radius + 'm. Market appears underserved — strong entry opportunity.';
}

// ── Build final output ────────────────────────────────────────────────────────
return [{
  json: {
    competitors:               ranked,
    total_found:               allPlaces.length,
    unique_found:              unique.length,
    validated_count:           totalCount,
    strong_count:              strongCount,
    moderate_count:            moderateCount,
    weak_count:                totalCount - strongCount - moderateCount,
    search_radius_m:           radius,
    biz_key:                   bizKey,
    area:                      area,
    city:                      city,
    opportunity_level:         opportunityLevel,
    opportunity_reason:        opportunityReason,
    saturation_level:          totalCount === 0 ? 'unknown'
                             : totalCount <= 3  ? 'low'
                             : totalCount <= 8  ? 'moderate'
                             : 'high',
    competitors_within_500m:   ranked.filter(function(c) { return c.distance_m !== null && c.distance_m <= 500; }).length,
    competitors_within_radius: ranked.filter(function(c) { return c.distance_m !== null && c.distance_m <= radius; }).length,
    data_source:               'google_places_nearbysearch',
    searched_at:               new Date().toISOString()
  }
}];
